var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"너무 어두워져서……. 아무것도 보이질 않아요.","JPN":"暗すぎて……何も見えません。","ENG":"It’s too dark in here... I can’t see anything.","TWN":"突然變得好暗……什麼都看不清楚。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"통신 상태도 먹통이야. 이래선 외부와 연락하기 어렵겠어.","JPN":"通信も繋がらない。これじゃ外部との連絡は厳しいな。","ENG":"Communication is blocked as well. We lost contact with the outside.","TWN":"而且也沒有任何訊號，根本無法與外界聯繫。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"우선은……. 다들 이것부터 쓰지. 야간 투시경이야.","JPN":"とりあえず……みんなこれを使ってくれ。暗視スコープだ。","ENG":"Well, first things first... use this. Night-vision goggles.","TWN":"我看……大家還是先戴上夜視鏡吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Oh, thank you.","TWN":"好，謝謝。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"준비성이 꽤 철저한데. 다시 봤어, 메이슨 씨.","JPN":"ずいぶん準備がいいな。メイソンさんのこと見直したぜ。","ENG":"You’re a very thorough person. That’s impressive, Mr. Mason.","TWN":"準備得滿周到的嘛！令人刮目相看喔，梅森！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"This place...","TWN":"這裡是……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"생각보다 훨씬 넓군. 단순한 보급 시설은 아닌 것 같은데.","JPN":"思ったよりもずっと広いな。単なる補給施設ではなさそうだ。","ENG":"It’s much bigger than I thought. This doesn’t look like an ordinary supply depot.","TWN":"比想像中還寬敞，應該不是單純的補給設施吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"뭐, 그래 봤자 버려진 곳이지.","JPN":"まあ、だとしても、今は捨てられた地に過ぎないさ。","ENG":"Still, it’s an abandoned facility.","TWN":"嗯，反正就是個荒廢的地方。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"각자 흩어져서 수색해 보자고. 이런 곳에서 오래 머물 필요는 없으니까.","JPN":"みんなで手分けして捜索してみよう。\\nこんな所、長居する必要はないからな。","ENG":"Let’s spread out and search. We don’t want to stay here too long.","TWN":"大家分頭去找吧，我們不要在這裡逗留太久。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"잠깐, 대령.","JPN":"ちょっと待て、大佐。","ENG":"Wait, Colonel.","TWN":"上校，先等一下。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"왜 그러지, 메이슨 씨?","JPN":"メイソンさん、どうした？","ENG":"What is it, Mr. Mason?","TWN":"怎麼了嗎，梅森？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"리플레이서…… 아니, 제이나 양이 뭔가 이상해.","JPN":"リプレイサー……いや、ジェイナの様子が何かおかしい。","ENG":"The Replacer—I mean, Jaina is acting strange.","TWN":"克隆……不是，婕娜好像怪怪的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"……이게 바로 그 노바급 리액터로군요.","JPN":"……これがあのノヴァ級リアクターなんですね。","ENG":"... So this is the Nova-Class Reactor.","TWN":"……這就是諾瓦反應爐嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"QUEEN_REPLACER_NULL_NULL","text":{"KOREA":"아직 불완전한 미스틸테인의 동력원으로 사용하면 우리에게 큰 힘이 될 겁니다.","JPN":"まだ不完全なミスティルテインの動力源として使えば、\\n我々にとって大きな力となるでしょう。","ENG":"This will be a great help for us if we use it as a power source for the imperfect Misteltein.","TWN":"米斯特丁還不完全，或許可以拿來當作它的動能，對我們應該會是一大助力。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"……아니, 노바급 리액터는 이대로 여기 동결할 생각이네.","JPN":"……いや、ノヴァ級リアクターはこのままここに凍結させるつもりだ。","ENG":"No, I’m going to freeze the Nova-Class Reactor here and now.","TWN":"……不，我打算將諾瓦反應爐就冷凍在這裡。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};